  100% { transform: translateY(0); }     /* Vuelve */
}

.bg-crane::before {
  content: "";
  position: absolute;
  width: 100px;
  height: 120px;
  background: #555;
  border-radius: 10px;
  top: 20%;
  left: 50%;
