  background: url('data:image/svg+xml;utf8,\
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 300 300">\
      <path d="M10,270 L290,30" stroke="%23555" stroke-width="6"/>\
      <path d="M290,30 L240,90" stroke="%23555" stroke-width="6"/>\      <path d="M240,90 L240,150" stroke="%23555" stroke-width="6"/>\
      <rect x="220" y="130" width="30" height="30" fill="%238bc34a"/>\
      <rect x="190" y="130" width="30" height="30" fill="%238bc34a"/>\
    </svg>') repeat;
  background-size: 300px 300px;
  mask-image: url('data:image/svg+xml;utf8,\
    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 300 300">\
      <rect width="300" height="300" fill="black"/>\
    </svg>');
}

/* Animación – sin cambios, solo la dejamos dentro del wrapper */
@keyframes lift {
  0%   { transform: translateY(0); }
  30%  { transform: translateY(-40px); }
  60%  { transform: translateY(-40px); }
  100% { transform: translateY(0); }
}
.bg-crane::before {
  content:"";
  position:absolute;
  width:100px; height:120px;
  background:#555;
  border-radius:10px;
